<template>
    <header class="header">
        <nav class="navbar">
            <div class="navbar-container">
                <div class="navbar-header">
                    <a href class="navbar-menu" @click.stop.prevent="toggleSidebar">
                        <i class="anticon" :class="mobileSidebar? 'icon-menu-unfold': 'icon-menu-fold'"></i>
                    </a>
                    <div class="nav-logo">
                        <router-link to="/">
                            {{$t('title.name')}}
                        </router-link>
                    </div>
                    
                    <a class="nav-theme" target="_blank" @click="changeTheme">
                        <i class="anticon" :class="theme=='light'?'icon-cloud':'icon-cloudo'"></i>
                    </a>
                </div>
            </div>
        </nav>
    </header>
</template>
<script>
import { mapState } from 'vuex';
export default {
    computed: {
        ...mapState({
            mobileSidebar: state => state.app.mobileSidebar,
            lang: state => state.app.lang,
            theme: state => state.app.theme
        })
    },
    watch: {
        '$route'(newVel, oldVel) {
            this.toggleSidebar(false)
        }
    },
    methods: {
        switchLang () {
            let lang = ''
            if (this.lang === 'en') {
                lang = 'zh'
            } else {
                lang = 'en'
            }
            this.$store.dispatch('switchLang', lang)
        },
        changeTheme() {
            if(this.theme == 'light') {
                this.$store.dispatch('ToggleTheme', 'dark');
                window.document.documentElement.setAttribute('data-theme', 'dark')
            } else {
                this.$store.dispatch('ToggleTheme', 'light');
                window.document.documentElement.setAttribute('data-theme', 'light')
            }
        },
        toggleSidebar(open) {
            this.$store.commit('TOGGLE_MOBILE_SIDEBAR', open)
        }
    }
}
</script>
<style lang="scss" scoped>
.header{
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: $navbar-height;
    background: #0593d3;
    // @include bg_color($background-color-light);
    z-index: 10;

    .navbar{

        .navbar-container{
            height: $navbar-height;

            .navbar-header{
                height: $navbar-height;
                display: flex;
                position: relative;
                align-items: center;
                width: 100%;
                justify-content: space-between;

                .navbar-menu{
                    border: none;
                    display: inline-block;
                    height: $navbar-height;
                    width: 20%;
                    line-height: $navbar-height;
                    text-align: center;
                    i{
                        @include font_color($font-color-light);
                    }
                }
            }
        }
    }
}
</style>


