<template>
    <div class="mobile-main">
        <div class="app-aside" :class="{'open': mobileSidebar }">
            <aside-view :class="{'open': mobileSidebar }"></aside-view>
        </div>
        <div class="app-aside__bg" v-if="mobileSidebar" @click="toggleSidebar(false)"></div>
        <header-view />
        <div class="main" :class="{'open': mobileSidebar }" ref="appMain">
            <main>
                <transition name="fade">
                    <router-view keep-alive />
                </transition>
            </main>
        </div>
    </div>
</template>
<script>
import HeaderView from './header'
import AsideView from './aside';
export default {
    components: {
        HeaderView,
        AsideView
    },
    computed: {
        mobileSidebar() {
            return this.$store.state.app.mobileSidebar
        }
    },
    methods: {
        toggleSidebar(open) {
            this.$store.commit('TOGGLE_MOBILE_SIDEBAR', open)
        }
    }
}
</script>
<style lang="scss" scoped>
.mobile-main{
    @include font_color($font-color-light);
    height: 100%;
    min-height: 100%;
    .app-aside{
        position: fixed;
        top: 0;
        right: 0;
        bottom: 0;
        left: 0;
        z-index: 1000;
        touch-action: none;
        background: rgba(0, 0, 0, 0.1);
        transform: translateX(-100%);
        transition: transform 0.3s ease-in-out;
        width: 270px;
        max-width: 100%;
        overflow-y: auto;
        &.open {
            transform: translateX(0%);
            background-color: #151617;
            box-shadow: 5px 0px 5px -2px #ccc;
            @include bg_color($background-color-light);
        }
    }
    .app-aside__bg{
        position: fixed;
        height: 100vh;
        width: 100%;
        top: 0;
        left: 0;
        background-color: rgba(0,0,0,.3);
        z-index: 999;
        transition: background-color 1s ease;
    }
    .main{
        transition: margin-left 0.3s ease-in-out;
        min-height: 100%;
        height: auto !important;
        padding-top: $navbar-height;
        width: 100%;
        overflow: hidden;
        
        &.open {
            position: fixed;
            margin-left: 270px;
            @include bg_color($background-color-light);
        }

        main{
            position: relative;
            width: 100%;
            .close-mask{
                position: fixed;
                width: 100%;
                height: 100%;
                right: 0;
                bottom: 0;
                z-index: 99999;
                background-color: #fff;
            }
        }
    }
}
</style>


