const app = {
    state: {
        device: 'desktop',
        layout: '',
        theme: 'dark',
        mobileSidebar: false,
        lang: localStorage.lang || 'zh'
    },
    mutations: {
        TOGGLE_DEVICE: (state, device) => {
            state.device = device
        },
        TOGGLE_LAYOUT_MODE: (state, layout) => {
            state.layout = layout
        },
        TOGGLE_THEME: (state, theme) => {
            state.theme = theme
        },
        TOGGLE_MOBILE_SIDEBAR: (state, open) => {
            state.mobileSidebar = open
        },
        SWITCH_LANG: (state, lang)=> {
            state.lang = lang
            window.app.$i18n.locale = lang
            localStorage.setItem('lang', lang)
        }
    },
    actions: {
        ToggleDevice ({ commit }, device) {
            commit('TOGGLE_DEVICE', device)
        },
        ToggleLayoutMode ({ commit }, mode) {
            commit('TOGGLE_LAYOUT_MODE', mode)
        },
        ToggleTheme ({ commit }, theme) {
            commit('TOGGLE_THEME', theme)
        },
        ToggleMobileSidebar ({ commit }, open) {
            commit('TOGGLE_MOBILE_SIDEBAR', open)
        },
        switchLang({ commit }, lang) {
            commit('SWITCH_LANG', lang)
        }
    }
}

export default app


