const data = {
    state: {
        bannerList: [],
        articleList: []
    },
    mutations: {
        SET_BANNER: (state, data)=> {
            state.bannerList = data
        },
        SET_ACTICLE: (state, data)=> {
            state.articleList = data
        }
    },
    actions: {
        SetBanner({ commit }, data) {
            commit('SET_BANNER', data)
        },
        SetActicle({ commit }, data) {
            commit('SET_ACTICLE', data)
        }
    }
}

export default data


