<template>
    <div id="app">
        <mobile-main-view v-if="device=='mobile'" />
        <pc-main-view v-else />
    </div>
</template>
<script>
import { mapState } from 'vuex';
import PcMainView from '@/components/layout/pc/main';
import MobileMainView from '@/components/layout/mobile/main';
import { AppDeviceEnquire } from '@/utils/mixin';
export default {
    name: 'App',
    mixins: [AppDeviceEnquire],
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    },
    components: {
        PcMainView,
        MobileMainView
    },
    mounted(){
        console.log('当前设备---', this.device);
        
    }
}
</script>
<style lang="scss" scoped>
#app{
    @include font_color($font-color-light);
    @include bg_color($background-color-light);
    height: auto;
}
</style>


