<template>
    <nav is="nav" class="navbar">
        <div class="container">
            <div class="nav-logo">
                <router-link to="/">
                    {{$t('title.name')}}
                </router-link>
            </div>
            <div class="nav-list flex">
                <router-link class="item" to="/">
                    <i class=""></i>
                    <span>首页</span>
                </router-link>
                <router-link class="item" to="/gank">
                    <i class=""></i>
                    <span>福利</span>
                </router-link>
                <router-link class="item" to="/about">
                    <i class=""></i>
                    <span>关于</span>
                </router-link>
                <a class="item" @click="changeTheme">
                    <i class="anticon" :class="theme=='light'?'icon-cloud':'icon-cloudo'"></i>
                </a>
                <a class="item" @click="switchLang">{{lang=='zh'?'en':'zh'}}</a>
            </div>
        </div>
    </nav>
</template>
<script>
import { mapState } from 'vuex';
export default {
    computed: {
        ...mapState({
            lang: state => state.app.lang,
            theme: state => state.app.theme
        })
    },
    mounted(){
        if(this.theme == 'light') {
            window.document.documentElement.setAttribute('data-theme', 'light')
        } else {
            window.document.documentElement.setAttribute('data-theme', 'dark')
        }
    },
    methods: {
        switchLang () {
            let lang = ''
            if (this.lang === 'en') {
                lang = 'zh'
            } else {
                lang = 'en'
            }
            this.$store.dispatch('switchLang', lang)
        },
        changeTheme() {
            if(this.theme == 'light') {
                this.$store.dispatch('ToggleTheme', 'dark');
                window.document.documentElement.setAttribute('data-theme', 'dark')
            } else {
                this.$store.dispatch('ToggleTheme', 'light');
                window.document.documentElement.setAttribute('data-theme', 'light')
            }
        }
    }
}
</script>


